import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePersonificationScript = async (
  healthKeyword: string,
  ctaProduct: string,
  frameCount: number,
  gender: string,
  voice: string,
  addressing: string,
  style: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      VĂN PHONG MIỀN BẮC (HÀ NỘI):
      - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
      - Cách dùng từ: "không", "vẫn", "thế này".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy.
    `;
  } else {
    dialectInstruction = `
      VĂN PHONG MIỀN NAM (SÀI GÒN):
      - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "nghen", "ha".
      - Cách dùng từ: "hông" (thay cho không), "thiệt" (thay cho thật), "dễ thương", "hết sảy".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng.
    `;
  }

  const prompt = `
    Nhiệm vụ: Tạo kịch bản TikTok nhân hóa bộ phận cơ thể.
    NỘI DUNG NGUỒN: "${healthKeyword}"
    SẢN PHẨM CTA: "${ctaProduct}"
    SỐ KHUNG HÌNH: ${frameCount}
    GIỚI TÍNH NHÂN VẬT: ${gender}
    GIỌNG ĐIỆU: ${voice}

    HƯỚNG DẪN QUAN TRỌNG:
    1. PHONG CÁCH: "${style}". Hãy viết nội dung hoàn toàn theo phong cách này.
    2. XƯNG HÔ: Bắt buộc sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe) xuyên suốt kịch bản. 
       - Ví dụ nếu chọn "tớ - cậu" thì bộ phận cơ thể gọi mình là "tớ" và gọi chủ nhân là "cậu".
    3. CẤU TRÚC:
       - Các khung đầu: Hook gây ấn tượng.
       - Các khung giữa: Nỗi đau/Insight từ góc nhìn bộ phận cơ thể.
       - Các khung kế cuối: Giới thiệu "${ctaProduct}".
       - Khung cuối: CTA.

    YÊU CẦU NGÔN NGỮ:
    - Giọng điệu: ${voice}. ${dialectInstruction}
    - Độ dài: Bắt buộc từ 160-190 ký tự mỗi đoạn.
    - Trả về mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();

  const isProductSection = script.toLowerCase().includes(ctaProduct.toLowerCase()) || 
                          script.toLowerCase().includes("sản phẩm") || 
                          script.toLowerCase().includes("cta");

  const prompt = `
    Style: 3D Animation Pixar/Disney style, vibrant colors, high quality.
    Setting: Inside the human body (stylized and clean).
    Character: A personified body part related to the context: "${healthKeyword.substring(0, 500)}". 
    Gender identity of character: ${gender}.
    The character must be cute/funny with expressive face, arms, legs, and a moving mouth. 
    Personality: Expressive and full of life.

    Action: "${script}".
    ${isProductSection ? `The character is naturally holding or using the product: "${ctaProduct}".` : ""}

    MANDATORY: 
    - NO TEXT, NO SUBTITLES, NO OVERLAYS.
    - 3D CGI look.
    ${regenNote ? `Additional instruction: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  productImages.forEach(img => contents.push({ inlineData: img }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generatePersonificationVeoPrompt = async (
  script: string,
  healthKeyword: string,
  gender: string,
  voice: string,
  style: string
): Promise<string> => {
  const ai = getAiClient();
  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). 
    Dựa trên kịch bản: "${script}" và phong cách "${style}", hãy tạo một prompt video hoàn chỉnh.

    CẤU TRÚC PROMPT (1 DÒNG):
    Đoạn 1: Nhân vật & bối cảnh 3D.
    Đoạn 2: Hành động mượt mà, biểu cảm khớp kịch bản.
    Đoạn 3: Góc quay camera chuyên nghiệp.
    Đoạn 4: Hậu cảnh nghệ thuật.
    Đoạn 5: Lời thoại (QUAN TRỌNG): ✨ Model speaks in ${voice} voice: "${script}"
    Đoạn 6: Thông số: 9:16, 4K, 3D Animation style, 60fps.

    YÊU CẦU: Chỉ trả về 1 dòng tiếng Anh duy nhất.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: systemPrompt }] }
  });
  return response.text?.trim().replace(/\n/g, ' ') || "";
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/personificationService';
import { PersonificationSegment } from '../types';

declare var JSZip: any;

const ADDRESSING_OPTIONS = [
  "em - anh", "em - chị", "em - bác", "tôi - bạn", "tớ - cậu", "mình - các bạn", "tao - mày", "con - ba/mẹ"
];

const STYLES = [
    { id: 'vui vẻ hài hước', label: 'Vui vẻ hài hước (Funny/Humorous)' },
    { id: 'châm biếm sarki', label: 'Châm biếm - Sarky (Sarcastic)' },
    { id: 'tâm sự trải lòng', label: 'Tâm sự trải lòng (Deep/Emotional)' },
    { id: 'kịch tính & cảm xúc', label: 'Kịch tính & cảm xúc (Dramatic)' },
    { id: 'thẳng thắn gắt', label: 'Thẳng thắn - Gắt (Brutal Honesty)' },
    { id: 'chuyên gia phân tích', label: 'Chuyên gia phân tích (Analytical)' },
    { id: 'truyền cảm hứng', label: 'Truyền cảm hứng (Motivational)' },
    { id: 'vlog đời thường', label: 'Vlog đời thường (Daily Vlog)' }
];

const PersonificationModule: React.FC = () => {
  const storageKey = "personification_project_v2";
  const [state, setState] = useState<any>({
    healthKeyword: '',
    ctaProduct: '',
    frameCount: 4,
    gender: 'Nữ',
    voice: 'Miền Bắc',
    addressing: 'em - anh',
    style: 'vui vẻ hài hước',
    productFiles: [],
    productPreviews: [],
    isGeneratingScript: false,
    segments: []
  });

  const productInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setState((p: any) => ({ 
          ...p, 
          ...parsed, 
          productFiles: [], 
          productPreviews: [], 
          isGeneratingScript: false,
          segments: (parsed.segments || []).map((s: any) => ({ ...s, image: { ...s.image, url: '' } })) 
        }));
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { productFiles, productPreviews, isGeneratingScript, segments, ...rest } = state;
      const safeSegments = segments.map((s: any) => ({ ...s, image: { ...s.image, url: '' } }));
      localStorage.setItem(storageKey, JSON.stringify({ ...rest, segments: safeSegments }));
    } catch (e) {}
  }, [state]);

  useEffect(() => {
    const handleExport = () => {
      const exportData = state.segments.map((seg: any, index: number) => ({
        stt: index + 1,
        inputs: {
          healthKeyword: state.healthKeyword,
          ctaProduct: state.ctaProduct,
          settings: {
            gender: state.gender,
            voice: state.voice,
            frameCount: state.frameCount,
            addressing: state.addressing,
            style: state.style
          }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data: exportData, moduleName: 'Nhan_Hoa_Bo_Phan' } }));
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;
      const firstItem = importedData[0];
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};

      const newState = {
        ...state,
        healthKeyword: inputs.healthKeyword || state.healthKeyword,
        ctaProduct: inputs.ctaProduct || state.ctaProduct,
        gender: settings.gender || state.gender,
        voice: settings.voice || state.voice,
        frameCount: settings.frameCount || importedData.length,
        addressing: settings.addressing || 'em - anh',
        style: settings.style || 'vui vẻ hài hước',
        segments: []
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        newState.segments.push({
          id: i + 1,
          content: item.script || '',
          image: { url: item.outputImage || '', loading: false, regenNote: '' },
          videoPrompt: { text: item.videoPrompt || '', loading: false, visible: true }
        });
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: Math.round(((i + 1) / importedData.length) * 100), complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 50));
      }
      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleProductUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = (Array.from(e.target.files) as File[]).slice(0, 5);
      const urls = files.map(f => URL.createObjectURL(f));
      setState((p: any) => ({ ...p, productFiles: files, productPreviews: urls }));
    }
  };

  const handleGenerateScript = async () => {
    if (!state.healthKeyword || !state.ctaProduct) return;
    setState((p: any) => ({ ...p, isGeneratingScript: true }));
    try {
      const scripts = await service.generatePersonificationScript(
        state.healthKeyword,
        state.ctaProduct,
        state.frameCount,
        state.gender,
        state.voice,
        state.addressing,
        state.style
      );
      const newSegments: PersonificationSegment[] = scripts.map((content, i) => ({
        id: i + 1,
        content,
        image: { url: '', loading: false, regenNote: '' },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setState((p: any) => ({ ...p, segments: newSegments, isGeneratingScript: false }));
    } catch (e) {
      setState((p: any) => ({ ...p, isGeneratingScript: false }));
    }
  };

  const handleGenImage = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s) }));
    try {
      const productParts = await Promise.all(state.productFiles.map((f: any) => service.fileToGenerativePart(f)));
      const url = await service.generatePersonificationImage(seg.content, productParts, state.healthKeyword, state.ctaProduct, state.gender, seg.image.regenNote);
      setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s) }));
    } catch (e) {
      setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: false } } : s) }));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s) }));
    try {
      const prompt = await service.generatePersonificationVeoPrompt(seg.content, state.healthKeyword, state.gender, state.voice, state.style);
      setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s) }));
    } catch (e) {
      setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s) }));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Loading ZIP library...");
    const zip = new JSZip();
    let count = 0;
    state.segments.forEach((seg: any, i: number) => {
      if (seg.image.url) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, seg.image.url.split(',')[1], { base64: true }); count++; }
    });
    if (count === 0) return alert("Không có ảnh.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a'); link.href = URL.createObjectURL(content); link.download = `nhan_hoa_${Date.now()}.zip`; link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">1. Ý tưởng / Bài viết nguồn</label>
              <textarea 
                value={state.healthKeyword}
                onChange={e => setState((p: any) => ({ ...p, healthKeyword: e.target.value }))}
                placeholder="Dán bài viết hoặc ý tưởng về sức khỏe..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-medium text-sm h-40 resize-none leading-relaxed"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">2. Sản phẩm muốn CTA</label>
              <input 
                type="text" 
                value={state.ctaProduct}
                onChange={e => setState((p: any) => ({ ...p, ctaProduct: e.target.value }))}
                placeholder="Ví dụ: trà thải độc gan..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none font-bold"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giới tính nhân vật</label>
                <select value={state.gender} onChange={e => setState((p: any) => ({ ...p, gender: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giọng điệu</label>
                <select value={state.voice} onChange={e => setState((p: any) => ({ ...p, voice: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                  <option value="Miền Bắc">Miền Bắc</option>
                  <option value="Miền Nam">Miền Nam</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Cách xưng hô</label>
                <select value={state.addressing} onChange={e => setState((p: any) => ({ ...p, addressing: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                  {ADDRESSING_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Phong cách kịch bản</label>
                <select value={state.style} onChange={e => setState((p: any) => ({ ...p, style: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                  {STYLES.map(s => <option key={s.id} value={s.id}>{s.label}</option>)}
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">3. Thời lượng video</label>
              <select value={state.frameCount} onChange={e => setState((p: any) => ({ ...p, frameCount: parseInt(e.target.value) }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                {Array.from({ length: 12 }, (_, i) => i + 4).map(n => <option key={n} value={n}>{n} khung hình - {n * 8}s</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">4. Ảnh sản phẩm mẫu (Tối đa 5)</label>
              <div onClick={() => productInputRef.current?.click()} className="min-h-[140px] border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center bg-slate-50 cursor-pointer hover:bg-slate-100 transition-all overflow-hidden p-2">
                {state.productPreviews.length > 0 ? (
                  <div className="grid grid-cols-5 gap-2 w-full">{state.productPreviews.map((url: string, i: number) => <img key={i} src={url} className="w-full aspect-square object-cover rounded-lg" />)}</div>
                ) : (
                  <div className="text-center"><svg className="w-8 h-8 text-slate-300 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tải ảnh sản phẩm</span></div>
