            <button onClick={handleGenerateScript} disabled={state.isGeneratingScript || !state.healthKeyword || !state.ctaProduct} className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter">
              {state.isGeneratingScript ? <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>XỬ LÝ...</> : "BẮT ĐẦU TẠO KỊCH BẢN"}
            </button>
          </div>
        </div>
      </div>

      {state.segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="flex justify-between items-center bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl">
            <div><h3 className="text-xl font-black text-white uppercase tracking-tight">Kịch bản chi tiết ({state.frameCount} khung)</h3><p className="text-xs text-orange-500 font-bold uppercase">{state.style} • {state.addressing}</p></div>
            <div className="flex gap-4">
              <button onClick={downloadAllImages} className="px-6 py-3 bg-white text-slate-900 text-xs font-black rounded-xl hover:bg-slate-100 transition-all uppercase">Tải ZIP Ảnh</button>
              <button onClick={() => { const text = state.segments.map((s: any) => s.videoPrompt.text).filter((t: string) => t).join('\n'); const blob = new Blob([text], { type: 'text/plain' }); const url = URL.createObjectURL(blob); const link = document.createElement('a'); link.href = url; link.download = 'nhan_hoa_prompts.txt'; link.click(); }} className="px-6 py-3 bg-orange-600 text-white text-xs font-black rounded-xl hover:bg-orange-700 transition-all uppercase">Tải Prompt</button>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {state.segments.map((seg: any) => (
              <div key={seg.id} className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? <img src={seg.image.url} className="w-full h-full object-cover" /> : <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">{seg.image.loading ? <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div> : <span className="text-[10px] font-black text-slate-300 uppercase">Ready to Gen</span>}</div>}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-3 py-1.5 rounded-full">CẢNH #{seg.id}</div>
                </div>
