import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePersonificationScript = async (
  healthKeyword: string,
  ctaProduct: string,
  frameCount: number,
  gender: string,
  voice: string,
  addressing: string,
  style: string,
  characterDescription: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      VĂN PHONG MIỀN BẮC (HÀ NỘI):
      - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
      - Cách dùng từ: "không", "vẫn", "thế này".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy.
    `;
  } else {
    dialectInstruction = `
      VĂN PHONG MIỀN NAM (SÀI GÒN):
      - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "nghen", "ha".
      - Cách dùng từ: "hông" (thay cho không), "thiệt" (thay cho thật), "dễ thương", "hết sảy".
      - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng.
    `;
  }

  const prompt = `
    Nhiệm vụ: Tạo kịch bản TikTok nhân hóa bộ phận cơ thể.
    NỘI DUNG NGUỒN: "${healthKeyword}"
    SẢN PHẨM CTA: "${ctaProduct}"
    SỐ KHUNG HÌNH: ${frameCount}
    GIỚI TÍNH NHÂN VẬT: ${gender}
    GIỌNG ĐIỆU: ${voice}
    MÔ TẢ CHI TIẾT NHÂN VẬT/BỐI CẢNH: "${characterDescription}"

    HƯỚNG DẪN QUAN TRỌNG:
    1. PHONG CÁCH: "${style}". Hãy viết nội dung hoàn toàn theo phong cách này.
    2. XƯNG HÔ: Bắt buộc sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe) xuyên suốt kịch bản. 
    3. CẤU TRÚC:
       - Các khung đầu: Hook gây ấn tượng mạnh.
       - Các khung giữa: Nỗi đau/Insight từ góc nhìn bộ phận cơ thể dựa trên bối cảnh mô tả.
       - Các khung kế cuối: Giới thiệu "${ctaProduct}".
       - Khung cuối: CTA.

    YÊU CẦU NGÔN NGỮ:
    - Giọng điệu: ${voice}. ${dialectInstruction}
    - Độ dài: Bắt buộc từ 160-190 ký tự mỗi đoạn.
    - Trả về mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  characterDescription: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();

  const isProductSection = script.toLowerCase().includes(ctaProduct.toLowerCase()) || 
                          script.toLowerCase().includes("sản phẩm") || 
                          script.toLowerCase().includes("cta");

  const prompt = `
    Style: 3D Animation Pixar/Disney style, vibrant colors, high quality.
    Setting: Inside the human body (stylized and clean) or based on: "${characterDescription}".
    Character: A personified body part related to the context: "${healthKeyword.substring(0, 500)}". 
    Gender identity of character: ${gender}.
    Character Details: "${characterDescription}".
    The character must be cute/funny with expressive face, arms, legs, and a moving mouth. 

    Action: "${script}".
    ${isProductSection ? `The character is naturally holding or using the product: "${ctaProduct}".` : ""}

    MANDATORY: 
    - NO TEXT, NO SUBTITLES, NO OVERLAYS.
    - 3D CGI look.
    ${regenNote ? `Additional instruction: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  productImages.forEach(img => contents.push({ inlineData: img }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generatePersonificationVeoPrompt = async (
  script: string,
  healthKeyword: string,
  gender: string,
  voice: string,
  style: string,
  characterDescription: string
): Promise<string> => {
  const ai = getAiClient();
  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). 
    Dựa trên kịch bản: "${script}", phong cách "${style}" và mô tả nhân vật: "${characterDescription}", hãy tạo một prompt video hoàn chỉnh.

    CẤU TRÚC PROMPT (1 DÒNG):
    Đoạn 1: Nhân vật & bối cảnh 3D dựa trên mô tả: ${characterDescription}.
    Đoạn 2: Hành động mượt mà, biểu cảm khớp kịch bản.
    Đoạn 3: Góc quay camera chuyên nghiệp.
    Đoạn 4: Hậu cảnh nghệ thuật.
    Đoạn 5: Lời thoại (QUAN TRỌNG): ✨ Model speaks in ${voice} voice: "${script}"
    Đoạn 6: Thông số: 9:16, 4K, 3D Animation style, 60fps.

    YÊU CẦU: Chỉ trả về 1 dòng tiếng Anh duy nhất.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: systemPrompt }] }
  });
  return response.text?.trim().replace(/\n/g, ' ') || "";
};

