                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? <img src={seg.image.url} className="w-full h-full object-cover" /> : <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">{seg.image.loading ? <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div> : <span className="text-[10px] font-black text-slate-300 uppercase">Ready to Gen</span>}</div>}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-3 py-1.5 rounded-full">CẢNH #{seg.id}</div>
                </div>
                <div className="p-6 flex flex-col flex-1 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-orange-600 uppercase">Lời thoại:</label>
                    <textarea value={seg.content} onChange={e => setState((p: any) => ({ ...p, segments: p.segments.map((s: any) => s.id === seg.id ? { ...s, content: e.target.value } : s) }))} className="w-full h-32 p-3 text-xs font-bold text-slate-700 bg-slate-50 border border-100 rounded-xl outline-none resize-none leading-relaxed" />
                    <div className="text-right"><span className={`text-[8px] font-black ${seg.content.length > 190 ? 'text-red-500' : 'text-slate-300'}`}>{seg.content.length}/190</span></div>
