                  <div className="mt-auto grid grid-cols-2 gap-2 pt-4">
                    <button onClick={() => handleGenImage(seg.id)} disabled={seg.image.loading} className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl hover:bg-black transition-all uppercase">Vẽ ảnh 3D</button>
                    <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt.loading} className="py-3 bg-orange-50 text-orange-600 text-[10px] font-black rounded-xl border border-orange-100 hover:bg-orange-100 transition-all uppercase">Prompt</button>
                  </div>
                </div>
                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2"><span className="text-[8px] font-black text-orange-500 uppercase">VEO-3 Prompt</span><button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] font-black text-white underline">COPY</button></div>
                    <p className="text-[9px] text-slate-300 italic opacity-80 leading-tight">"{seg.videoPrompt.text}"</p>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

