        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  characterDescription: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();

  const isProductSection = script.toLowerCase().includes(ctaProduct.toLowerCase()) || 
                          script.toLowerCase().includes("sản phẩm") || 
                          script.toLowerCase().includes("cta");

  const prompt = `
    Style: 3D Animation Pixar/Disney style, vibrant colors, high quality.
    Setting: Inside the human body (stylized and clean) or based on: "${characterDescription}".
    Character: A personified body part related to the context: "${healthKeyword.substring(0, 500)}". 
    Gender identity of character: ${gender}.
    Character Details: "${characterDescription}".
    The character must be cute/funny with expressive face, arms, legs, and a moving mouth. 
    Personality: Sassy, bossy, or pitiful based on context.

    Action: "${script}".
    ${isProductSection ? `The character is naturally holding or using the product: "${ctaProduct}".` : ""}

    MANDATORY: 
    - NO TEXT, NO SUBTITLES, NO OVERLAYS.
    - 3D CGI look.
    ${regenNote ? `Additional instruction: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  productImages.forEach(img => contents.push({ inlineData: img }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

