export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  characterDescription: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = true; // Mặc định module nhân hóa là 3D Animation

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = regenNote && noProductKeywords.some(kw => regenNote.toLowerCase().includes(kw));

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${ctaProduct}" MUST MATCH the input reference images provided.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - DO NOT change shape, proportions, or physical parts.
       - LOCK the product appearance exactly to the original photos provided.
       - Hình ảnh tạo ra phải là góc medium shot. chiếm 3/4 khung hình.
       - QUAN TRỌNG: Đồng nhất về kích thước sản phẩm so sánh với tỷ lệ nhân vật trên khung hình trong tất cả các hình ảnh.
       - CONSISTENT SCALE (QUAN TRỌNG): Đảm bảo kích thước và tỷ lệ của sản phẩm so với khung hình phải đồng nhất 100% qua tất cả các cảnh.
       - Bắt buộc giữ nguyên sản phẩm. Vật thể phải khớp với ảnh gốc 1:1.
       - Always refer to the context, characters, and product (especially product proportions) in the result before creating the image.
       - Lưu ý: nếu sản phẩm là thời trang thì chỉ lấy trang phục, bỏ qua khuôn mặt người trong ảnh sản phẩm.
       `}
  `;

  const prompt = `
    Style: 3D Animation Pixar/Disney style, vibrant colors, high quality.
    Setting: Inside the human body (stylized and clean) or based on: "${characterDescription}".
    Character: A personified body part related to the context: "${healthKeyword.substring(0, 500)}". 
