import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const FORBIDDEN_TERMS = `Facebook, Shopee, Lazada, Tiki, Zalo, Sale sốc, Mua ngay, Cam kết, Top 1, Giá rẻ nhất.`;

export const generatePersonificationScript = async (
  healthKeyword: string,
  ctaProduct: string,
  frameCount: number,
  gender: string,
  voice: string,
  addressing: string,
  style: string,
  characterDescription: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ. Không dùng: nha, nè, thiệt, hông.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, hen, hông, thiệt. Không dùng: nhé, ạ, thế.`;

  const prompt = `
    Nhiệm vụ: Tạo kịch bản TikTok nhân hóa bộ phận cơ thể dựa trên NỘI DUNG NGUỒN.
    NỘI DUNG NGUỒN: "${healthKeyword}"
    SẢN PHẨM CTA: "${ctaProduct}"
    SỐ KHUNG HÌNH: ${frameCount}
    GIỚI TÍNH: ${gender}
    GIỌNG ĐIỆU: ${voice}
    MÔ TẢ NHÂN VẬT TỔNG THỂ: "${characterDescription}"

    HƯỚNG DẪN XỬ LÝ:
    1. Phân tích nội dung nguồn để tìm ra bộ phận cơ thể liên quan nhất (VD: gan, tim, phổi, mắt...).
    2. Tạo kịch bản từ góc nhìn bộ phận đó đang "tâm sự" hoặc "mắng" chủ nhân.
    3. PHONG CÁCH: "${style}". Dùng ngôn ngữ đời thường, có thể kèm Slang Gen Z (ét ô ét, chê, mãi mận, ra dẻ...).
    4. XƯNG HÔ: Bắt buộc dùng cặp "${addressing}".

    CẤU TRÚC:
    - Khung đầu: Hook ấn tượng.
    - Khung giữa: Nỗi đau/Insight.
    - Khung kế cuối: Giới thiệu "${ctaProduct}".
    - Khung cuối: CTA điều hướng.

    YÊU CẦU ĐỘ DÀI: Bắt buộc từ 160-190 ký tự mỗi đoạn. Trả về mảng JSON string.
    TUYỆT ĐỐI KHÔNG DÙNG: ${FORBIDDEN_TERMS}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  globalCharDesc: string,
  sceneIdea: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = true;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "no product", "remove product"];
  const isNoProductRequested = (regenNote + sceneIdea).toLowerCase().split(' ').some(word => noProductKeywords.includes(word));

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. Must look like high-quality 3D CGI Pixar/Disney style.
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY):
       - The product "${ctaProduct}" MUST MATCH the input reference images provided.
       - PRESERVE PATTERNS & TEXTURES: Any pattern, logo, or design must be preserved.
       - LOCK the product appearance exactly to the original photos provided.
       - Kích thước sản phẩm và nhân vật phải đồng nhất 100% qua tất cả các cảnh.
       - Bắt buộc giữ nguyên sản phẩm 1:1.`}
  `;

  const prompt = `
    Style: 3D Animation Pixar style, vibrant colors, polished CGI.
    Character: A personified body part related to "${healthKeyword.substring(0, 200)}".
    Gender Identity: ${gender}.
    Global Appearance: "${globalCharDesc}".

    !!! SPECIFIC SCENE IDEA (PRIORITY): "${sceneIdea}" !!!
    Action matches dialogue: "${script}".

    The character must have expressive face, arms, legs, and moving mouth.
    Personality: Sassy, bossy, or pitiful based on context.

    ${visualRules}
    ${regenNote ? `User feedback: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (!isNoProductRequested) {
    productImages.forEach(img => contents.push({ inlineData: img }));
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generatePersonificationVeoPrompt = async (
  script: string,
  healthKeyword: string,
  gender: string,
  voice: string,
  style: string,
  globalDesc: string,
  sceneIdea: string
): Promise<string> => {
  const ai = getAiClient();
  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Tạo prompt video dài 8 giây.

    CẤU TRÚC PROMPT (1 DÒNG DUY NHẤT):
    Đoạn 1: Nhân vật & bối cảnh 3D dựa trên: "${globalDesc}" và ý tưởng cảnh này: "${sceneIdea}".
    Đoạn 2: Hành động khớp lời thoại: "${script}".
    Đoạn 3: Góc quay Pan/Zoom/Dolly mượt mà.
    Đoạn 4: Hậu cảnh nội tạng nghệ thuật hóa hoặc bối cảnh: "${sceneIdea}".
    Đoạn 5: Lời thoại: ✨ Model speaks in ${voice} voice (${gender}): "${script}"
    Đoạn 6: 9:16, 4K, 3D Animation style, 60fps.

    YÊU CẦU: Trả về 1 dòng tiếng Anh duy nhất (trừ phần lời thoại).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: systemPrompt }] }
  });
  return response.text?.trim().replace(/\n/g, ' ') || "";
};

