                    <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt.loading} className="py-3 bg-orange-50 text-orange-600 text-[10px] font-black rounded-xl border border-orange-100 hover:bg-orange-100 transition-all uppercase tracking-tighter">Prompt</button>
