/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting, casual environment.";

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, ${lifestyleStyle} vibe, vibrant but natural colors, expressive character, polished CGI.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, authentic skin textures, cinematic but realistic natural lighting.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // !!! STRICT FACE EXCLUSIVITY RULES (BỔ SUNG) !!!
  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE (MANDATORY) !!!:
       1. YOU MUST USE THE EXACT facial features, hair color/style, and bone structure from the provided FACE_REFERENCE image.
       2. COMPLETELY IGNORE AND EXCLUDE any faces, eyes, or identities found in OUTFIT_REFERENCE or PRODUCT_REFERENCE images.
       3. If other reference images contain people, treat them ONLY as faceless mannequins; DO NOT COPY their faces or identity.
       4. The character's face MUST come 100% from FACE_REFERENCE only.`
    : `IDENTITY: Adult Vietnamese ${gender} matching description: "${characterDescription}".`;

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${productName}" MUST MATCH the input reference images provided 1:1.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - DO NOT change shape, proportions, or physical parts.
       - LOCK the product appearance exactly to the original photos provided.
       - Hình ảnh tạo ra phải là góc medium shot. chiếm 3/4 khung hình.
       - QUAN TRỌNG: Đồng nhất về kích thước sản phẩm so sánh với tỷ lệ nhân vật trên khung hình trong tất cả các hình ảnh.
       - CONSISTENT SCALE (QUAN TRỌNG): Đảm bảo kích thước và tỷ lệ của sản phẩm so với khung hình phải đồng nhất 100% qua tất cả các cảnh.
       - Bắt buộc giữ nguyên sản phẩm. Vật thể phải khớp với ảnh gốc 1:1.
       - Always refer to the context, characters, and product (especially product proportions) in the result before creating the image.
       - Lưu ý: nếu sản phẩm là thời trang thì chỉ lấy trang phục, bỏ qua khuôn mặt người trong ảnh sản phẩm.
       `}
  `;

  const characterFidelityRule = `
    !!! CRITICAL CHARACTER FIDELITY (PRIORITY) !!!:
    Follow những chi tiết này cho nhân vật: "${characterDescription}".
    Gender: Adult Vietnamese ${gender}.
    - MANDATORY: If description mentions body type or clothing style, apply it 100%. 
  `;

  const outfitRule = outfitImagePart ? `
    OUTFIT: Use textures and style from OUTFIT_REFERENCE. Casual/daily fashion: "${outfitDescription}".
    REMINDER: ONLY use the clothes from OUTFIT_REFERENCE, COMPLETELY IGNORE the face and identity of the person shown in that reference image.
  ` : "";

  const backgroundRule = backgroundReferencePart 
    ? `ENVIRONMENT: Use the exact background setting, layout, and atmosphere from the BACKGROUND_REFERENCE image.`
    : `ENVIRONMENT: Set the scene in a natural ${backgroundNote || 'daily lifestyle setting'}.`;

  const poseInstruction = poseLabel ? `CHARACTER POSE (MANDATORY): The person is ${poseLabel}. Ensure the interaction with the product matches this pose perfectly.` : "";

  const sceneInstruction = `SCENE: Context: "${scriptPart}". Action should feel spontaneous and unposed. ${poseInstruction}`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });

  if (!isNoProductRequested) {
    referenceImageParts.forEach(part => contents.push({ inlineData: part }));
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".
      - [QUAN TRỌNG: sản phẩm là một vật thể cứng, rắn chắc. KHÔNG ĐƯỢC BIẾN DẠNG, KHÔNG ĐƯỢC LÀM BIẾN DẠNG, KHÔNG ĐƯỢC TẠO HOẠT HÌNH CHO THIẾT BỊ. Giữ cho các cạnh sắc nét và tĩnh hoàn hảo. Duy trì tỷ lệ hình học 1:1 với hình ảnh tham khảo].
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`;

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.
  !!! CRITICAL IDENTITY RULE !!!: Maintain 100% facial and appearance consistency with the face provided in the reference image (0. Ảnh mặt mẫu). EXCLUDE any facial features or identity from background outfit shots or product images.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Nhân vật người Việt Nam. Đặc điểm diễn xuất và giọng nói: ${voiceDetail}. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Một không gian sống hiện đại, sạch sẽ. ${is3D ? "Môi trường 3D sống động." : "Ánh sáng điện ảnh chân thực."}
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Cách nhân vật di chuyển và tương tác với Camera. Có Pan hoặc Dolly hoặc zoom hoặc tracking shot vào sản phẩm hoặc nhân vật (tuyệt đối không thay đổi bối cảnh và nhân vật).
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceDetail} characteristics (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}, Không có nhạc nền, Tuyệt đối không hiệu ứng chuyển cảnh hay lật trang ở cuối video.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  }
  if (generatedImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Video prompt generation error", error);
    return "Error generating video prompt.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/shopee8sService';
import { Shopee8sProduct, ScriptParts, VideoPromptState, GeneratedImage } from '../types';
import ScriptSection from '../components/ScriptSection';
import ImageCard from '../components/ImageCard';

declare var JSZip: any;

const VOICE_OPTIONS = [
  "Giọng Bắc 20-40 tuổi",
  "Giọng Nam 20-40 tuổi",
  "Giọng Bắc 50-60 tuổi",
  "Giọng Nam 50-60 tuổi",
  "Giọng Bắc 60-80 tuổi",
  "Giọng Nam 60-80 tuổi"
];

const ADDRESSING_OPTIONS = [
  "em - anh chị",
  "em - các bác",
  "tôi - các bạn",
  "tớ - các cậu",
  "mình - các bạn",
  "tao - mày",
  "tui - mấy bà",
  "tui - mấy ní",
  "tui - các bác",
  "tui - mấy ông",
  "mình - cả nhà",
  "mình - mọi người"
];

const Shopee8sModule: React.FC = () => {
  const storageKey = "shopee8s_project_v8_voice_addressing";
  const [products, setProducts] = useState<Shopee8sProduct[]>(
    Array.from({ length: 5 }, (_, i) => ({
      id: i + 1,
      name: '',
      usp: '',
      background: '',
      action: '',
      file: null,
      previewUrl: null,
      script: null,
      images: {},
      videoPrompts: {},
      isLoading: false
    }))
  );

  const [activeProductId, setActiveProductId] = useState<number>(1);
  const [faceFile, setFaceFile] = useState<File | null>(null);
  const [facePreview, setFacePreview] = useState<string | null>(null);
  const [gender, setGender] = useState<string>('Nữ');
  const [voice, setVoice] = useState<string>(VOICE_OPTIONS[0]);
  const [addressing, setAddressing] = useState<string>('em - anh chị');
  const [imageStyle, setImageStyle] = useState<'Realistic' | '3D'>('Realistic');
  const [commonNote, setCommonNote] = useState('');
  const [isGlobalLoading, setIsGlobalLoading] = useState(false);

  const fileInputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const faceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.products) {
          setProducts(prev => prev.map(p => {
            const savedP = parsed.products.find((sp: any) => sp.id === p.id);
            return savedP ? { 
              ...p, 
              ...savedP, 
              file: null, 
              previewUrl: null, 
              isLoading: false,
              images: savedP.images || {},
              videoPrompts: savedP.videoPrompts || {}
            } : p;
          }));
        }
        if (parsed.commonNote) setCommonNote(parsed.commonNote);
        if (parsed.gender) setGender(parsed.gender);
        if (parsed.voice) setVoice(parsed.voice);
        if (parsed.addressing) setAddressing(parsed.addressing);
        if (parsed.imageStyle) setImageStyle(parsed.imageStyle);
      }
    } catch (e) { console.error("Restore fail", e); }
  }, []);

  useEffect(() => {
    try {
      const persistentProducts = products.map(({ file, previewUrl, isLoading, images, videoPrompts, ...rest }) => {
        const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
           acc[key] = { ...images[key], url: '' }; 
           return acc;
        }, {});
        return { 
          ...rest, 
          images: safeImages, 
          videoPrompts: videoPrompts || {} 
        };
      });
      localStorage.setItem(storageKey, JSON.stringify({ products: persistentProducts, commonNote, gender, voice, addressing, imageStyle }));
    } catch (e) { }
  }, [products, commonNote, gender, voice, addressing, imageStyle]);

  // Handle Import/Export
  useEffect(() => {
    const handleExport = () => {
      const exportData: any[] = [];
      let stt = 1;
      products.forEach(p => {
        if (!p.script) return;
        ['v1', 'v2', 'v3', 'v4'].forEach(key => {
          exportData.push({
            stt: stt++,
            inputs: {
              productName: p.name,
              usp: p.usp,
              background: p.background,
              action: p.action,
              settings: {
                gender,
                voice,
                addressing,
                imageStyle,
                commonNote
              }
            },
            script: (p.script as any)[key],
            outputImage: p.images[key]?.url || '',
            videoPrompt: p.videoPrompts[key]?.text || ''
          });
        });
      });

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Shopee_Video_8s' } 
      }));
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;

      const smartFind = (obj: any, keys: string[]) => {
        const lowerKeys = keys.map(k => k.toLowerCase());
        const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
        return foundKey ? obj[foundKey] : undefined;
      };

      const firstItem = importedData[0];
      const globalInputs = smartFind(firstItem, ['inputs', 'data']) || {};
      const globalSettings = smartFind(globalInputs, ['settings']) || {};

      const newProducts = [...products];
      const total = importedData.length;

      setGender(smartFind(globalSettings, ['gender']) || gender);
      setVoice(smartFind(globalSettings, ['voice']) || voice);
      setAddressing(smartFind(globalSettings, ['addressing', 'xưng hô']) || addressing);
      setImageStyle(smartFind(globalSettings, ['imageStyle']) || imageStyle);
      setCommonNote(smartFind(globalSettings, ['commonNote']) || commonNote);

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const inputs = smartFind(item, ['inputs', 'data']) || {};

        const prodIndex = Math.floor(i / 4);
        if (prodIndex >= newProducts.length) break;

        const prod = newProducts[prodIndex];
        prod.name = smartFind(inputs, ['productName', 'name']) || prod.name;
        prod.usp = smartFind(inputs, ['usp', 'keyword']) || prod.usp;
        prod.background = smartFind(inputs, ['background', 'bối cảnh']) || prod.background;
        prod.action = smartFind(inputs, ['action', 'hành động']) || prod.action;

        if (!prod.script) prod.script = { v1: '', v2: '', v3: '', v4: '' };

        const sceneIdx = (i % 4) + 1;
        const key = `v${sceneIdx}`;

        prod.script[key] = smartFind(item, ['script', 'content', 'text']) || '';
        prod.images[key] = { 
          url: smartFind(item, ['outputImage', 'image', 'base64']) || '', 
          loading: false 
        };
        prod.videoPrompts[key] = { 
          text: smartFind(item, ['videoPrompt', 'prompt']) || '', 
          loading: false, 
          visible: true 
        };

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setProducts(newProducts);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [products, gender, voice, addressing, imageStyle, commonNote]);

  const updateProduct = (id: number, updates: Partial<Shopee8sProduct>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const updateProductImage = (productId: number, imageKey: string, imgUpdates: Partial<GeneratedImage>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newImages = { ...p.images };
      newImages[imageKey] = { ...(newImages[imageKey] || { url: '', loading: false }), ...imgUpdates };
      return { ...p, images: newImages };
    }));
  };

  const updateProductVideoPrompt = (productId: number, promptKey: string, promptUpdates: Partial<VideoPromptState>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newPrompts = { ...p.videoPrompts };
      newPrompts[promptKey] = { ...(newPrompts[promptKey] || { text: '', loading: false, visible: false }), ...promptUpdates };
      return { ...p, videoPrompts: newPrompts };
    }));
  };

  const handleFileChange = (id: number, file: File | null) => {
    if (!file) return;
    const url = URL.createObjectURL(file);
    updateProduct(id, { file, previewUrl: url });
  };

  const handleGenerateAll = async () => {
    const productsToGen = products.filter(p => p.file && p.name);
    if (productsToGen.length === 0) {
      alert("Vui lòng tải ảnh và nhập tên cho ít nhất một sản phẩm.");
      return;
    }

    setIsGlobalLoading(true);

    try {
      const generationPromises = productsToGen.map(async (product) => {
        try {
          const script = await service.generateShopee8sScript(product.name, product.usp, voice, addressing, gender);
          const initialImages: any = {};
          const initialPrompts: any = {};
          ['v1', 'v2', 'v3', 'v4'].forEach(k => {
            initialImages[k] = { url: '', loading: false, customPrompt: '' };
            initialPrompts[k] = { text: '', loading: false, visible: false };
          });
          return { id: product.id, script, initialImages, initialPrompts };
        } catch (error) {
          console.error(`Script error product ${product.id}:`, error);
          return { id: product.id, error: true };
        }
      });

      const results = await Promise.all(generationPromises);

      setProducts(prev => prev.map(p => {
        const res = results.find(r => r.id === p.id);
        if (res && !res.error) {
          return {
            ...p,
            script: res.script,
            images: res.initialImages,
            videoPrompts: res.initialPrompts,
            isLoading: false
          };
        }
        return { ...p, isLoading: false };
      }));

    } catch (error) {
      console.error("Global generation error:", error);
      alert("Có lỗi xảy ra khi tạo kịch bản hàng loạt.");
    } finally {
      setIsGlobalLoading(false);
    }
  };

  const handleGenImageForKey = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.file || !product.script) return;

    updateProductImage(productId, key, { loading: true, error: undefined });

    try {
      const imagePart = await service.fileToGenerativePart(product.file);
      const facePart = faceFile ? await service.fileToGenerativePart(faceFile) : null;
      const isFollowUp = key === 'v2' || key === 'v4';

      const latestProductState = products.find(p => p.id === productId);
      const customP = latestProductState?.images[key]?.customPrompt || "";

      const charDesc = [
        product.action ? `Action: ${product.action}` : "",
        product.background ? `Background: ${product.background}` : "",
        commonNote, 
        customP
      ].filter(Boolean).join(". ");

      const imgUrl = await service.generateShopee8sImage(
        [imagePart], 
        product.name, 
        (product.script as any)[key], 
        charDesc,
        facePart,
        isFollowUp,
        imageStyle,
        gender
      );

      updateProductImage(productId, key, { url: imgUrl, loading: false });
    } catch (error) {
      console.error(error);
      updateProductImage(productId, key, { loading: false, error: 'Lỗi tạo ảnh' });
    }
  };

  const handleGenVideoPrompt = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.script) return;

    updateProductVideoPrompt(productId, key, { text: '', loading: true, visible: true });

    try {
      const productImagePart = product.file ? await service.fileToGenerativePart(product.file) : null;
      const customP = product.images[key]?.customPrompt || "";
      const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
      const isNoProduct = noProductKeywords.some(kw => customP.toLowerCase().includes(kw));

      const enhancedScript = product.action 
        ? `${(product.script as any)[key]} (Action hint: ${product.action})`
        : (product.script as any)[key];

      const prompt = await service.generateShopee8sVeoPrompt(
        product.name,
        enhancedScript,
        gender,
        voice,
        productImagePart?.data,
        product.images[key]?.url,
        isNoProduct,
        imageStyle
      );

      updateProductVideoPrompt(productId, key, { text: prompt, loading: false, visible: true });
    } catch (error) {
      updateProductVideoPrompt(productId, key, { text: 'Lỗi tạo prompt.', loading: false, visible: true });
    }
  };

  const handleBulkPromptForProduct = async (productId: number) => {
    const keys = ['v1', 'v2', 'v3', 'v4'];
    for (const key of keys) {
        await handleGenVideoPrompt(productId, key);
    }
  };

  const handleBulkImageForProduct = async (productId: number) => {
    const keys = ['v1', 'v2', 'v3', 'v4'];
    for (const key of keys) {
        await handleGenImageForKey(product.id, key);
    }
  };

  const handleDownloadAllImagesZip = async () => {
    if (typeof JSZip === 'undefined') return;
    const zip = new JSZip();
    let sequenceIndex = 1;
    for (const product of products) {
      for (const key of ['v1', 'v2', 'v3', 'v4']) {
        const img = product.images[key];
        if (img?.url) {
          zip.file(`${String(sequenceIndex).padStart(2, '0')}.png`, img.url.split(',')[1], { base64: true });
          sequenceIndex++;
        }
      }
    }
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(content);
    link.download = "shopee8s_images.zip";
    link.click();
  };

  const handleDownloadAllPromptsTxt = () => {
    let allPrompts = "";
    for (const product of products) {
      for (const key of ['v1', 'v2', 'v3', 'v4']) {
        const p = product.videoPrompts[key];
        if (p?.text) allPrompts += p.text.replace(/\n/g, ' ') + "\n";
      }
    }
    const blob = new Blob([allPrompts], { type: 'text/plain' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "shopee8s_prompts.txt";
    link.click();
  };

  const productsWithResults = products.filter(p => p.script);
  const hasResults = productsWithResults.length > 0;
  const hasAnyMedia = products.some(p => 
    (Object.values(p.images) as GeneratedImage[]).some(img => img.url) || 
    (Object.values(p.videoPrompts) as VideoPromptState[]).some(pr => pr.text)
  );

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input Grid */}
      <div className="bg-white rounded-[1.5rem] border border-slate-200 p-8 shadow-sm space-y-8">
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
          {products.map((p) => (
            <div 
              key={p.id}
              onClick={() => setActiveProductId(p.id)}
              className={`flex flex-col rounded-[1rem] border-2 p-3 transition-all cursor-pointer group relative ${
                activeProductId === p.id 
                  ? 'border-[#ff5722] ring-1 ring-[#ff5722]/10 bg-white' 
                  : 'border-[#f1f5f9] bg-white hover:border-slate-300'
              }`}
            >
              <div className="flex items-center gap-2 mb-3">
                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-all ${
                  activeProductId === p.id ? 'border-[#ff5722] bg-[#ff5722]' : 'border-slate-300 bg-white'
                }`}>
                  {activeProductId === p.id && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className={`text-[11px] font-bold ${activeProductId === p.id ? 'text-[#ff5722]' : 'text-slate-500'}`}>
                  Sản phẩm {p.id}
                </span>
              </div>

              <div 
                onClick={(e) => { e.stopPropagation(); fileInputRefs.current[p.id]?.click(); }}
                className="aspect-[4/5] bg-[#f8fafc] rounded-lg border border-dashed border-slate-200 mb-3 flex flex-col items-center justify-center overflow-hidden transition-all group-hover:bg-[#f1f5f9] relative"
              >
                {p.previewUrl ? (
                  <img src={p.previewUrl} className="w-full h-full object-cover" alt={`p${p.id}`} />
                ) : (
                  <div className="text-center p-2 opacity-40">
                    <svg className="w-8 h-8 mx-auto text-slate-400 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    <span className="text-[10px] font-bold uppercase tracking-tighter">TẢI ẢNH</span>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={el => { fileInputRefs.current[p.id] = el; }}
                  onChange={(e) => handleFileChange(p.id, e.target.files?.[0] || null)}
                  className="hidden" 
                  accept="image/*"
                />
              </div>

              <div className="space-y-2">
                <input 
                  type="text" 
                  value={p.name}
                  onClick={(e) => e.stopPropagation()}
                  onChange={(e) => updateProduct(p.id, { name: e.target.value })}
                  placeholder="Tên sản phẩm..."
                  className="w-full text-[11px] p-2 bg-white border border-slate-200 rounded-md outline-none focus:border-[#ff5722]/40 font-medium placeholder:text-slate-300"
