const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const getVoiceDetailedInstruction = (voiceLabel: string) => {
  const mapping: Record<string, string> = {
    "Giọng Bắc 20-40 tuổi": "20-40 tuổi, giọng miền Bắc, năng động, nhịp độ nhanh, vui vẻ, tông cao, hào hứng. Dùng từ: nhé, ạ, thế, chứ. Không dùng: nha, nè, thiệt, hông.",
    "Giọng Nam 20-40 tuổi": "20-40 tuổi, giọng miền Nam, năng động, nhịp độ nhanh, vui vẻ, tông cao, hào hứng. Dùng từ: nha, nè, thiệt, hông. Không dùng: nhé, ạ, thế.",
    "Giọng Bắc 50-60 tuổi": "50-60 tuổi, giọng miền Bắc, giọng trầm, vang, ổn định, uy quyền, đáng tin cậy, hào hứng. Dùng từ: nhé, ạ, thế, chứ.",
    "Giọng Nam 50-60 tuổi": "50-60 tuổi, giọng miền Nam, giọng trầm, vang, ổn định, uy quyền, đáng tin cậy, hào hứng. Dùng từ: nha, nè, thiệt, hông.",
    "Giọng Bắc 60-80 tuổi": "60-80 tuổi, giọng miền Bắc, khàn, hào sảng, chân chất, thực tế, hào hứng. Dùng từ: nhé, ạ, thế, chứ.",
    "Giọng Nam 60-80 tuổi": "60-80 tuổi, giọng miền Nam, khàn, hào sảng, chân chất, thực tế, hào hứng. Dùng từ: nha, nè, thiệt, hông."
  };
  return mapping[voiceLabel] || voiceLabel;
};

export const generateShopee8sScript = async (productName: string, usp: string, voice: string, addressing: string, gender: string): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `Bạn là chuyên gia content Shopee chuyên nghiệp chuyên tạo video viral.
  Nhiệm vụ: Tạo kịch bản cho 2 video quảng cáo Shopee (mỗi video dài 16 giây).
  Sản phẩm: "${productName}". USP: "${usp}".
  NHÂN VẬT: Giới tính ${gender}, Đặc điểm giọng nói: ${voiceDetail}.

  CẤU TRÚC:
  - VIDEO 1: v1 (8s đầu - Hook) và v2 (8s sau - Giải pháp). v1 và v2 kết nối thành 1 câu chuyện.
  - VIDEO 2: v3 (8s đầu - Góc nhìn thực tế) và v4 (8s sau - CTA). v3 và v4 kết nối thành 1 câu chuyện.

  YÊU CẦU ĐỘ DÀI (BẮT BUỘC):
  - Mỗi phần (v1, v2, v3, v4) PHẢI CÓ độ dài từ 160 đến 185 ký tự. 

  YÊU CẦU NỘI DUNG:
  - XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe) xuyên suốt 100%.
  - Văn phong phải khớp hoàn toàn với mô tả: ${voiceDetail}.
  - Không dùng từ cấm: Shopee, Lazada, Tiki, Facebook, TikTok Shop, QR, Giá rẻ nhất, Sale sốc, Mua ngay đi.

  Trả về duy nhất JSON: { "v1": "...", "v2": "...", "v3": "...", "v4": "..." }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: { v1: { type: Type.STRING }, v2: { type: Type.STRING }, v3: { type: Type.STRING }, v4: { type: Type.STRING } },
          required: ["v1", "v2", "v3", "v4"]
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (error) {
    return { v1: '', v2: '', v3: '', v4: '' };
  }
};

export const generateShopee8sImage = async (
  imageParts: any[], 
  productName: string, 
  scriptPart: string, 
  charDesc: string,
  facePart: any | null,
  isFollowUp: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  gender: string = 'Nữ'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  // !!! STRICT FACE EXCLUSIVITY RULES !!!
  const identityRule = facePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE !!!:
       1. YOU MUST USE THE EXACT facial features, hair, and bone structure from the provided FACE_REFERENCE image.
       2. COMPLETELY IGNORE AND EXCLUDE any faces, eyes, or identities found in PRODUCT_REFERENCE images.`
    : `SUBJECT: Adult Vietnamese character. Gender: ${gender}. ${charDesc}`;

  const baseStyle = is3D 
    ? "High-quality 3D Animation Pixar/Disney style, vibrant colors, expressive 3D character design, polished CGI, masterpiece."
    : "Photorealistic high-end commercial RAW PHOTO, 8k resolution, cinematic lighting, authentic skin textures.";

  const visualRules = `
    CRITICAL VISUAL RULES:
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS.
    2. The background must be CLEAN and FREE of written words.
    3. NO UI elements, NO speech bubbles, NO watermarks.

    STRICT PRODUCT FIDELITY (MANDATORY):
       - The product "${productName}" MUST MATCH the input reference image 1:1.
       - PRESERVE PATTERNS & TEXTURES. LOCK the product appearance exactly.
       - The product must be a solid, fixed object. No distortion.
  `;

  const consistencyRule = isFollowUp 
    ? "CRITICAL: Maintain ABSOLUTE consistency in character appearance and background as previous scene."
    : "Establish clear character appearance.";

  const prompt = `
    STYLE: ${baseStyle} 
    RATIO: 9:16 aspect ratio.
    ${identityRule}
    ${visualRules}
    ${consistencyRule}
    SCENE: Action: ${scriptPart}. Note: ${charDesc}.
  `;

  const contents: any[] = [{ text: prompt }];
  if (facePart) contents.push({ inlineData: facePart });
  if (imageParts.length > 0) contents.push({ inlineData: imageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (error) { throw error; }
};

