                  className="w-full p-3 border rounded-xl h-20 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giới tính nhân vật</label>
                <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold">
