import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const splitScriptIntoSegments = async (originalScript: string): Promise<string[]> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Phân chia kịch bản văn bản dưới đây thành các đoạn nhỏ để làm video TikTok.
    Kịch bản: "${originalScript}"

    YÊU CẦU NGHIÊM NGẶT:
    1. Mỗi đoạn BẮT BUỘC có độ dài từ 160 đến 190 ký tự.
    2. Tuyệt đối không được ngắn hơn 160 ký tự.
    3. Giữ nguyên nội dung và tính mạch lạc, không làm mất ý nghĩa của câu.
    4. Trả về kết quả dưới dạng một mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Split script failed", e);
    return [];
  }
};

export const generatePersonifiedImage = async (
  segmentContent: string,
  characterIdea: string,
  gender: string
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    STYLE: 3D Animation Pixar/Disney style, high-quality CGI, vibrant colors, polished textures.
    RATIO: 9:16 aspect ratio.

    CONCEPT: Personification. 
    CHARACTER DESCRIPTION: ${characterIdea || "A personified object matching the story"}.
    SCENE ACTION: Based on this content: "${segmentContent}".

    ENVIRONMENT: Professional 3D environment, cinematic lighting.
    GENDER THEME: Vietnamese ${gender}.

    STRICT VISUAL RULES:
    1. NO TEXT, NO LOGOS, NO WATERMARKS.
    2. Character must have expressive eyes and mouth.
    3. If character is an object (leaf, fruit, organ), it must be next to or interacting with a Vietnamese ${gender} person.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generateVideoPromptV2 = async (
  segmentContent: string,
  characterIdea: string,
  gender: string
): Promise<string> => {
  const ai = getAiClient();
  const voiceGender = gender === 'Nam' ? 'Male' : 'Female';

  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Dựa trên nội dung kịch bản và ý tưởng nhân vật, hãy tạo prompt video 6 đoạn.

    CẤU TRÚC BẮT BUỘC (TRẢ VỀ TRÊN 1 DÒNG DUY NHẤT):
    Đoạn 1: Character & Setting. Describe the personified character and a Vietnamese ${gender} person in a clean environment.
    Đoạn 2: Action & Interaction. Describe natural interaction matching the script. NO products allowed. Maintain visual consistency.
    Đoạn 3: Camera. Tự sáng tạo các chuyển động máy theo dạng POV (Point of View).
    Đo đoạn 4: Hậu cảnh & đạo cụ. Detailed description of background and atmosphere.
    Đoạn 5: Lời thoại (QUAN TRỌNG NHẤT). ✨ Model speaks in Northern Vietnamese voice (${voiceGender}): "${segmentContent}"
    Đoạn 6: Thông số kỹ thuật. 9:16 aspect ratio, 4K resolution, realistic style, cinematic lighting.

    YÊU CẦU: Trả về 1 đoạn văn bản Tiếng Anh duy nhất (trừ phần lời thoại). Không tiêu đề đoạn.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: systemPrompt }] }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (e) {
    return "Error generating video prompt.";
  }
};

import React, { useState, useEffect } from 'react';
import * as service from '../services/personification2Service';
import { Personification2Segment } from '../types';

declare var JSZip: any;

const Personification2Module: React.FC = () => {
  const storageKey = "personification2_v1_stable";
  const [originalScript, setOriginalScript] = useState('');
  const [gender, setGender] = useState('Nữ');
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<Personification2Segment[]>([]);

  // LocalStorage Restore
  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setOriginalScript(parsed.originalScript || '');
        setGender(parsed.gender || 'Nữ');
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      } catch (e) {}
    }
  }, []);

  // LocalStorage Sync
  useEffect(() => {
    const toSave = { originalScript, gender, segments: segments.map(s => ({ ...s, image: { ...s.image, url: '' } })) };
    localStorage.setItem(storageKey, JSON.stringify(toSave));
  }, [originalScript, gender, segments]);

  const handleSplitScript = async () => {
    if (!originalScript.trim()) return;
    setIsProcessing(true);
    try {
      const splitTexts = await service.splitScriptIntoSegments(originalScript);
      const newSegments = splitTexts.map((text, i) => ({
        id: i + 1,
        content: text,
        characterIdea: '',
        image: { url: '', loading: false },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));
    try {
      const url = await service.generatePersonifiedImage(seg.content, seg.characterIdea, gender);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi' } } : s));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateVideoPromptV2(seg.content, seg.characterIdea, gender);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleDownloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP Lib not loaded.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
        count++;
      }
    });
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a'); link.href = URL.createObjectURL(content); link.download = `nhan_hoa_2_images.zip`; link.click();
  };

  const handleDownloadAllPrompts = () => {
    const text = segments.map(s => s.videoPrompt.text).filter(t => t).join('\n');
    if (!text) return alert("Chưa có prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts_nhan_hoa_2.txt'; link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[2rem] border border-slate-200 p-8 shadow-sm mb-8">
        <div className="space-y-6">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">1. Nhập kịch bản văn bản gốc</label>
            <textarea 
              value={originalScript}
              onChange={e => setOriginalScript(e.target.value)}
              placeholder="Dán kịch bản của bạn vào đây..."
              className="w-full h-48 p-5 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-medium text-sm leading-relaxed resize-none"
            />
          </div>

          <div className="flex flex-col md:flex-row gap-4 items-center">
            <div className="w-full md:w-48">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Giới tính nhân vật</label>
              <select value={gender} onChange={e => setGender(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold">
                <option value="Nữ">Nữ</option>
                <option value="Nam">Nam</option>
              </select>
            </div>
            <button 
              onClick={handleSplitScript}
              disabled={isProcessing || !originalScript.trim()}
              className="w-full md:flex-1 py-4 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:bg-orange-700 transition-all uppercase tracking-widest disabled:opacity-50"
            >
              {isProcessing ? "ĐANG XỬ LÝ..." : "CHIA NHỎ KỊCH BẢN (160-190 KÝ TỰ)"}
            </button>
          </div>
        </div>
      </div>

      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
              <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100">
                  {seg.image.url ? <img src={seg.image.url} className="w-full h-full object-cover" /> : null}
                  {seg.image.loading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm">
                      <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                      <span className="mt-4 text-[10px] font-black text-orange-600 uppercase animate-pulse">Đang tạo ảnh 3D...</span>
                    </div>
                  )}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full">#{seg.id}</div>
                </div>

                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <div className="flex justify-between items-center px-1">
                      <label className="text-[9px] font-black text-orange-600 uppercase">Kịch bản đoạn {seg.id}:</label>
                      <span className={`text-[8px] font-bold ${seg.content.length > 190 || seg.content.length < 160 ? 'text-red-500' : 'text-slate-400'}`}>{seg.content.length}/190</span>
                    </div>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-32 p-3 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white resize-none"
                    />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-blue-600 uppercase px-1">Nhân vật nhân hóa:</label>
                    <textarea 
                      value={seg.characterIdea}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, characterIdea: e.target.value } : s))}
                      placeholder="VD: Quả cam có mắt mũi đang vui vẻ..."
                      className="w-full h-20 p-3 bg-blue-50/50 border border-blue-100 rounded-2xl text-[11px] font-medium outline-none focus:bg-white resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all"
                    >
                      Vẽ ảnh 3D
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading}
                      className="py-3 bg-orange-100 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-200 hover:bg-orange-200 transition-all"
                    >
                      Tạo Prompt
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[8px] font-black text-emerald-500 uppercase">VEO-3 Prompt Ready</span>
                      <button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] text-white underline font-black">COPY</button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-4 h-4 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <p className="text-[9px] text-slate-400 italic leading-snug">"{seg.videoPrompt.text}"</p>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>

          <div className="flex flex-col md:flex-row items-center justify-center gap-6 py-12 border-t border-slate-200">
            <button 
              onClick={handleDownloadAllImages}
              className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl hover:bg-black transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              Tải bộ ảnh (.ZIP)
            </button>
            <button 
              onClick={handleDownloadAllPrompts}
              className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-3xl shadow-xl hover:bg-orange-700 transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              Tải bộ Prompt (.TXT)
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

