import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

const getVoiceDetailedInstruction = (voiceLabel: string) => {
  const isNorth = voiceLabel.includes("Bắc");
  const dialectInstruction = isNorth ? `
    VĂN PHONG MIỀN BẮC (HÀ NỘI):
    - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
    - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy.
  ` : `
    VĂN PHONG MIỀN NAM (SÀI GÒN):
    - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "ha".
    - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng.
  `;

  const ageMapping: Record<string, string> = {
    "Giọng Bắc 20-40 tuổi": "20-40 tuổi, miền Bắc, năng động, vui vẻ, tông cao.",
    "Giọng Nam 20-40 tuổi": "20-40 tuổi, miền Nam, năng động, vui vẻ, tông cao.",
    "Giọng Bắc 50-60 tuổi": "50-60 tuổi, miền Bắc, trầm, vang, uy quyền.",
    "Giọng Nam 50-60 tuổi": "50-60 tuổi, miền Nam, trầm, vang, uy quyền.",
    "Giọng Bắc 60-80 tuổi": "60-80 tuổi, miền Bắc, khàn, hào sảng, chân chất.",
    "Giọng Nam 60-80 tuổi": "60-80 tuổi, miền Nam, khàn, hào sảng, chân chất."
  };

  return (ageMapping[voiceLabel] || voiceLabel) + "\n" + dialectInstruction;
};

const getVoiceTag = (voiceLabel: string) => {
  if (voiceLabel.includes("Bắc")) return "Northern Vietnamese";
  return "Southern Vietnamese";
};

export const splitScriptIntoSegments = async (originalScript: string, voice: string, addressing: string): Promise<string[]> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Nhiệm vụ: Phân chia kịch bản văn bản dưới đây thành các đoạn nhỏ để làm video TikTok.
    Kịch bản gốc: "${originalScript}"

    YÊU CẦU NGÔN NGỮ & GIỌNG ĐIỆU:
    - Đặc điểm giọng nói: ${voiceDetail}
    - XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe).

    YÊU CẦU KỸ THUẬT:
    1. Mỗi đoạn BẮT BUỘC có độ dài từ 160 đến 190 ký tự.
    2. Tuyệt đối không được ngắn hơn 160 ký tự.
    3. Giữ nguyên nội dung và tính mạch lạc, không làm mất ý nghĩa của câu.
    4. Trả về kết quả dưới dạng một mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Split script failed", e);
    return [];
  }
};

export const generatePersonifiedImage = async (
  segmentContent: string,
  characterIdea: string,
  gender: string
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    STYLE: 3D Animation Pixar/Disney style, high-quality CGI, vibrant colors, polished textures.
    RATIO: 9:16 aspect ratio.

    CONCEPT: Personification. 
    CHARACTER DESCRIPTION: ${characterIdea || "A personified object matching the story"}.
    SCENE ACTION: Based on this content: "${segmentContent}".

    ENVIRONMENT: Professional 3D environment, cinematic lighting.
    GENDER THEME: Vietnamese ${gender}.

    STRICT VISUAL RULES:
    1. NO TEXT, NO LOGOS, NO WATERMARKS.
    2. Character must have expressive eyes and mouth.
    3. If character is an object (leaf, fruit, organ), it must be next to or interacting with a Vietnamese ${gender} person.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Image generation failed", e);
    throw e;
  }
};

export const generateVideoPromptV2 = async (
  segmentContent: string,
  characterIdea: string,
  gender: string,
  voice: string
): Promise<string> => {
  const ai = getAiClient();
  const voiceTag = getVoiceTag(voice);

  const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Dựa trên nội dung kịch bản và ý tưởng nhân vật, hãy tạo prompt video 6 đoạn.

    CẤU TRÚC BẮT BUỘC (TRẢ VỀ TRÊN 1 DÒNG DUY NHẤT):
    Đoạn 1: Nhân vật & bối cảnh. Mô tả nhân vật nhân hóa 3D và một người Việt Nam ${gender} trong môi trường sạch sẽ, chuyên nghiệp. (Tỉ lệ 9:16).
    Đoạn 2: Hành động & tương tác. Mô tả sự tương tác tự nhiên giữa nhân vật và bối cảnh khớp với kịch bản. TUYỆT ĐỐI không thêm sản phẩm. Giữ nguyên diện mạo nhân vật như ảnh tham chiếu.
    Đoạn 3: Góc quay & chuyển động máy. Tự sáng tạo các chuyển động máy theo dạng POV (Point of View) chuyên nghiệp.
    Đoạn 4: Hậu cảnh & đạo cụ. Mô tả chi tiết không gian background, ánh sáng và bầu không khí.
    Đoạn 5: Lời thoại (QUAN TRỌNG NHẤT). Bạn phải sử dụng CHÍNH XÁC định dạng sau:
    ✨ Model speaks in ${voiceTag} voice (${gender}): "${segmentContent}"
    Đoạn 6: Thông số kỹ thuật. 9:16 aspect ratio, 4K resolution, realistic style, cinematic lighting, 60fps.

    YÊU CẦU: Trả về 1 đoạn văn bản Tiếng Anh duy nhất (trừ phần lời thoại). Không để tiêu đề "Đoạn 1", "Đoạn 2".
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: systemPrompt }] }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (e) {
    return "Error generating video prompt.";
  }
};

