    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setOriginalScript(parsed.originalScript || '');
        setGender(parsed.gender || 'Nữ');
        setVoice(parsed.voice || VOICE_OPTIONS[0]);
        setAddressing(parsed.addressing || '');
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      } catch (e) {}
    }
  }, []);

  // LocalStorage Sync (Chỉ lưu text để tránh tràn quota)
  useEffect(() => {
    const toSave = { 
      originalScript, 
      gender, 
      voice, 
      addressing, 
      segments: segments.map(s => ({ 
        ...s, 
        image: { ...s.image, url: '' },
        videoPrompt: { ...s.videoPrompt, loading: false }
      })) 
    };
    localStorage.setItem(storageKey, JSON.stringify(toSave));
  }, [originalScript, gender, voice, addressing, segments]);

  // HANDLE GLOBAL IMPORT / EXPORT
  useEffect(() => {
    const handleExport = () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          originalScript,
          settings: {
            gender,
            voice,
            addressing
          },
          segmentData: {
            characterIdea: seg.characterIdea
          }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Nhan_Hoa_2_Project' } 
      }));
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};

      setOriginalScript(inputs.originalScript || '');
      setGender(settings.gender || 'Nữ');
      setVoice(settings.voice || VOICE_OPTIONS[0]);
      setAddressing(settings.addressing || '');

      const newSegments: Personification2Segment[] = [];
      const total = importedData.length;

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = item.inputs || {};

        newSegments.push({
          id: i + 1,
          content: item.script || '',
          characterIdea: itemInputs.segmentData?.characterIdea || '',
          image: { url: item.outputImage || '', loading: false },
          videoPrompt: { 
            text: item.videoPrompt || '', 
            loading: false, 
            visible: !!item.videoPrompt 
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setSegments(newSegments);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, originalScript, gender, voice, addressing]);

  const handleSplitScript = async () => {
    if (!originalScript.trim()) return;
    setIsProcessing(true);
    try {
      const splitTexts = await service.splitScriptIntoSegments(originalScript, voice, addressing);
      const newSegments = splitTexts.map((text, i) => ({
        id: i + 1,
        content: text,
        characterIdea: '',
        image: { url: '', loading: false },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));
    try {
      const url = await service.generatePersonifiedImage(seg.content, seg.characterIdea, gender);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi' } } : s));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateVideoPromptV2(seg.content, seg.characterIdea, gender, voice);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkImage = async () => {
    for (const seg of segments) {
      await handleGenImage(seg.id);
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
      await handleGenPrompt(seg.id);
    }
  };

  const handleDownloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP Lib not loaded.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
        count++;
      }
    });
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a'); link.href = URL.createObjectURL(content); link.download = `nhan_hoa_2_images.zip`; link.click();
  };

  const handleDownloadAllPrompts = () => {
    const text = segments.map(s => s.videoPrompt.text).filter(t => t).join('\n');
    if (!text) return alert("Chưa có prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts_nhan_hoa_2.txt'; link.click();
  };

  const hasGeneratedMedia = segments.some(s => s.image.url || s.videoPrompt.text);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[2rem] border border-slate-200 p-8 shadow-sm mb-8">
        <div className="space-y-6">
          <div className="flex justify-between items-center px-1">
             <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">1. Nhập kịch bản văn bản gốc</label>
             <span className="text-[10px] font-bold text-orange-500 uppercase">Beta Version 3.0</span>
          </div>
          <textarea 
            value={originalScript}
            onChange={e => setOriginalScript(e.target.value)}
            placeholder="Dán kịch bản của bạn vào đây..."
            className="w-full h-48 p-5 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-medium text-sm leading-relaxed resize-none"
          />

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Giới tính</label>
              <select value={gender} onChange={e => setGender(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold outline-none focus:border-orange-500 appearance-none">
                <option value="Nữ">Nữ</option>
                <option value="Nam">Nam</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Vùng miền</label>
              <select value={voice} onChange={e => setVoice(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold outline-none focus:border-orange-500 appearance-none">
                {VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Xưng hô</label>
              <div className="relative group">
                <input 
                  list="nhanhoa2-addressing-list"
                  value={addressing} 
                  onChange={e => setAddressing(e.target.value)}
                  placeholder="VD: tui - mấy ní"
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold outline-none focus:border-orange-500 text-sm"
                />
                <datalist id="nhanhoa2-addressing-list">
                  {ADDRESSING_OPTIONS.map(opt => <option key={opt} value={opt} />)}
                </datalist>
              </div>
            </div>
            <button 
              onClick={handleSplitScript}
              disabled={isProcessing || !originalScript.trim()}
              className="w-full py-3.5 bg-orange-600 text-white font-black rounded-xl shadow-lg hover:bg-orange-700 transition-all uppercase tracking-widest disabled:opacity-50"
            >
              {isProcessing ? "ĐANG CHIA..." : "CHIA KỊCH BẢN"}
            </button>
          </div>
        </div>
      </div>

      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          {/* Bulk Action Header */}
          <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6">
