                  <h3 className="text-white font-black text-lg uppercase tracking-tight">Điều khiển tự động</h3>
                  <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest">Đã chia {segments.length} phân cảnh</p>
              </div>
              <div className="flex flex-wrap justify-center gap-3">
                  <button 
                    onClick={handleBulkImage}
                    className="px-6 py-3 bg-orange-600 text-white text-[10px] font-black rounded-xl hover:bg-orange-700 transition-all uppercase flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
                    Tự động tạo tất cả ảnh
                  </button>
                  <button 
                    onClick={handleBulkPrompt}
                    className="px-6 py-3 bg-white text-slate-900 text-[10px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                    Tự động viết tất cả prompt
                  </button>
              </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
