                <div onClick={() => faceInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden group">
                  {state.facePreviewUrl ? (
                    <>
                      <img src={state.facePreviewUrl} className="h-full object-cover" />
                      <button 
